function runProgressAnimation(durationMs, setter) {
  return new Promise((resolve) => {
    const start = performance.now()
    function frame(now) {
      const t = Math.min(1, (now - start) / durationMs)
      const eased = 1 - (1 - t) * (1 - t)
      setter(eased * 100)
      if (t < 1) {
        activeAnimRaf = requestAnimationFrame(frame)
      } else {
        setter(100)
        activeAnimRaf = null
        resolve()
      }
    }
    activeAnimRaf = requestAnimationFrame(frame)
  })
}

